pub fn run(
        session: &mut Session,
        cfg: &AgentLoopConfig,
        transport: &dyn LoopTransport,
        registry: &ToolRegistry,
        tool_ctx: &ToolContext,
        sink: &dyn AuditSink,
        user_prompt: &str,
    ) -> Result<LoopOutcome, AgentLoopError> {
        session.ensure_spawn_emitted(&cfg.run_id, cfg.task_id.as_deref(), sink);

        session.append_message(Message::user_text(user_prompt));

        let advertised: Vec<String> = match cfg.advertised_tools.as_ref() {
            Some(set) => set.clone(),
            None => cfg.tool_allowlist.clone(),
        };
        let tool_specs = build_tool_specs(registry, &advertised);
        let allowlist: Vec<&str> = cfg.tool_allowlist.iter().map(String::as_str).collect();

        let started = Instant::now();
        let mut total_tokens_observed: u64 = 0;
        let mut cumulative_usage = TurnUsage::default();
        let mut trace: Vec<IterationTrace> = Vec::new();
        let mut last_text_reply = String::new();
        let mut iteration: u32 = 0;

        loop {
            iteration += 1;
            check_deadline(cfg, started)?;
            if iteration > cfg.max_iterations {
                return Err(AgentLoopError::MaxIterations {
                    limit: cfg.max_iterations,
                    observed: iteration - 1,
                });
            }

            let turn_req = TurnRequest {
                system: if session.system_prompt().is_empty() {
                    None
                } else {
                    Some(session.system_prompt())
                },
                messages: session.history(),
                tools: &tool_specs,
                cache_hint: cfg.cache_hint,
                max_response_tokens: cfg.max_response_tokens,
            };

            let TurnResponse {
                content,
                stop_reason,
                usage,
                raw_request_body,
                raw_response_body,
                endpoint,
                http_status,
            } = invoke_transport(transport, sink, cfg, session.id(), iteration, &turn_req)?;

            total_tokens_observed = total_tokens_observed
                .saturating_add(usage.input_tokens)
                .saturating_add(usage.output_tokens)
                .saturating_add(usage.cache_creation_input_tokens);
            accumulate(&mut cumulative_usage, &usage);

            // Minimal debug hook — raw bytes retained in audit, not dropped.
            drop((raw_request_body, raw_response_body, endpoint, http_status));

            if total_tokens_observed > cfg.max_total_tokens {
                return Err(AgentLoopError::TokenBudget {
                    limit: cfg.max_total_tokens,
                    observed: total_tokens_observed,
                });
            }
            check_deadline(cfg, started)?;

            let (text_part, assistant_blocks, tool_calls) = classify_content(&content);
            if !text_part.is_empty() {
                last_text_reply = text_part;
            }

            session.append_message(Message::assistant(assistant_blocks));

            let mut iter_tool_names = Vec::new();
            let mut iter_denials = Vec::new();
            let mut user_tool_results: Vec<ContentBlock> = Vec::new();

            for (tool_use_id, tool_name, input) in tool_calls {
                iter_tool_names.push(tool_name.clone());

                if !is_tool_allowed(&tool_name, &allowlist) {
                    let reason = "tool not in allowlist".to_string();
                    let denial_payload = serde_json::json!({
                        "tool_name": &tool_name,
                        "tool_use_id": &tool_use_id,
                        "reason": &reason,
                        "input": &input,
                    });
                    let _ =
                        sink.write_blob(&serde_json::to_vec(&denial_payload).unwrap_or_default());
                    sink.emit(&LoopAuditEvent::PolicyDenial {
                        ts: Utc::now(),
                        run_id: cfg.run_id.clone(),
                        session_id: session.id().to_string(),
                        iteration,
                        tool_name: tool_name.clone(),
                        reason,
                    });
                    iter_denials.push(tool_name.clone());
                    sink.emit(&LoopAuditEvent::IterationBoundary {
                        ts: Utc::now(),
                        run_id: cfg.run_id.clone(),
                        session_id: session.id().to_string(),
                        iteration,
                        continues: false,
                    });
                    trace.push(IterationTrace {
                        iteration,
                        stop_reason,
                        tool_calls: iter_tool_names,
                        policy_denials: iter_denials,
                        usage: usage.clone(),
                    });
                    return Err(AgentLoopError::PolicyDenied {
                        tool_name,
                        iteration,
                    });
                }

                let input_bytes = serde_json::to_vec(&input).unwrap_or_default();
                let input_sha256 = sink.write_blob(&input_bytes);
                sink.emit(&LoopAuditEvent::ToolCallRequested {
                    ts: Utc::now(),
                    run_id: cfg.run_id.clone(),
                    session_id: session.id().to_string(),
                    iteration,
                    tool_name: tool_name.clone(),
                    tool_use_id: tool_use_id.clone(),
                    input_sha256,
                });

                let outcome = dispatch(registry, tool_ctx, &tool_name, input);
                let output_bytes = serde_json::to_vec(&outcome.output).unwrap_or_default();
                let output_sha256 = sink.write_blob(&output_bytes);
                sink.emit(&LoopAuditEvent::ToolCallResult {
                    ts: Utc::now(),
                    run_id: cfg.run_id.clone(),
                    session_id: session.id().to_string(),
                    iteration,
                    tool_name: tool_name.clone(),
                    tool_use_id: tool_use_id.clone(),
                    outcome: if outcome.is_error {
                        "error".to_string()
                    } else {
                        "ok".to_string()
                    },
                    output_sha256,
                    duration_ms: outcome.duration_ms,
                });

                let tool_text = match serde_json::to_string(&outcome.output) {
                    Ok(s) => s,
                    Err(err) => format!("{{\"error\":\"serialize: {err}\"}}"),
                };
                user_tool_results.push(ContentBlock::ToolResult {
                    tool_use_id,
                    content: tool_text,
                    is_error: outcome.is_error,
                });
            }

            let continues =
                matches!(stop_reason, StopReason::ToolUse) && !user_tool_results.is_empty();
            sink.emit(&LoopAuditEvent::IterationBoundary {
                ts: Utc::now(),
                run_id: cfg.run_id.clone(),
                session_id: session.id().to_string(),
                iteration,
                continues,
            });
            trace.push(IterationTrace {
                iteration,
                stop_reason,
                tool_calls: iter_tool_names,
                policy_denials: iter_denials,
                usage: usage.clone(),
            });

            if !continues {
                let terminate_reason = match stop_reason {
                    StopReason::MaxTokens => TerminateReason::MaxTokens,
                    StopReason::EndTurn => TerminateReason::Stop,
                    _ => TerminateReason::Other,
                };
                return Ok(LoopOutcome {
                    final_message: last_text_reply,
                    usage: cumulative_usage,
                    terminate_reason,
                    trace,
                });
            }

            session.append_message(Message::user_blocks(user_tool_results));
        }
    }

pub fn dispatch(
    registry: &ToolRegistry,
    ctx: &ToolContext,
    name: &str,
    input: Value,
) -> DispatchOutcome {
    let started = Instant::now();
    let result = registry.execute(name, ctx, input);
    let duration_ms = started.elapsed().as_millis();
    match result {
        Ok(output) => DispatchOutcome {
            output,
            is_error: false,
            duration_ms,
        },
        Err(err) => DispatchOutcome {
            output: tool_error_value(&err),
            is_error: true,
            duration_ms,
        },
    }
}

pub fn execute_tool_command(
        &self,
        name: &str,
        input: Value,
        agent_override: Option<String>,
        model_override: Option<String>,
    ) -> Result<Value, OrbitError> {
        let allowed_tools = read_activity_tools_from_env();
        let (agent_name, model_name) = resolve_agent_identity(agent_override, model_override);
        let proc_allowed_programs = read_proc_allowed_programs_from_env();
        let cwd = std::env::current_dir()
            .ok()
            .map(|path| path.to_string_lossy().into_owned());
        let tool_context = ToolContext {
            cwd,
            allowed_tools,
            agent_name,
            model_name,
            workspace_root: None,
            proc_allowed_programs,
            ..Default::default()
        };
        self.run_tool_with_context_and_role(name, input, Role::Admin, tool_context)
    }

fn run_tool_with_context_and_role(
        &self,
        name: &str,
        input: Value,
        role: Role,
        tool_context: ToolContext,
    ) -> Result<Value, OrbitError> {
        OrbitRuntime::run_tool_with_context_and_role(self, name, input, role, tool_context)
    }

pub(crate) fn run_tool_with_role(
        &self,
        name: &str,
        input: Value,
        role: Role,
    ) -> Result<Value, OrbitError> {
        self.run_tool_with_context_and_role(name, input, role, ToolContext::default())
    }

pub(crate) fn run_tool_with_context_and_role(
        &self,
        name: &str,
        input: Value,
        _role: Role,
        mut tool_context: ToolContext,
    ) -> Result<Value, OrbitError> {
        if tool_context.cwd.is_none() {
            tool_context.cwd = std::env::current_dir()
                .ok()
                .map(|cwd| cwd.to_string_lossy().into_owned());
        }

        let resolved_task_id = match tool_context.orbit_host.as_ref() {
            Some(host) => host.task_scope().task_id,
            None => resolve_task_id_from_context(self, &tool_context)?,
        };

        if tool_context.orbit_host.is_none() {
            tool_context.orbit_host =
                Some(super::build_orbit_tool_host(self, resolved_task_id.clone()));
        }

        // Ensure fs tools always have a workspace boundary for sandboxing.
        if tool_context.workspace_root.is_none() {
            tool_context.workspace_root = resolve_workspace_root_from_context(
                self,
                resolved_task_id.as_deref(),
                &tool_context,
            )?;
        }
        if tool_context.policy_engine.is_none() {
            tool_context.policy_engine = Some(Arc::new(self.policy_engine().clone()));
        }
        if tool_context.fs_profile.is_none() {
            tool_context.fs_profile = read_activity_fs_profile_from_env();
        }

        self.check_tool_enabled(name)?;

        if !tool_context.allowed_tools.is_empty()
            && !tool_context.allowed_tools.iter().any(|t| t == name)
        {
            self.with_mutation(|| {
                Ok((
                    (),
                    OrbitEvent::PolicyDenied {
                        tool: name.to_string(),
                    },
                ))
            })?;
            return Err(OrbitError::PolicyDenied(format!(
                "tool '{name}' is not in the activity allowlist"
            )));
        }

        let output = match self
            .tool_registry()
            .execute(name, &tool_context, input)
            .map_err(redact_sensitive_env_error)
        {
            Ok(output) => output,
            Err(OrbitError::PolicyDenied(reason)) => {
                self.with_mutation(|| {
                    Ok((
                        (),
                        OrbitEvent::PolicyDenied {
                            tool: name.to_string(),
                        },
                    ))
                })?;
                return Err(OrbitError::PolicyDenied(reason));
            }
            Err(error) => return Err(error),
        };
        let output = redact_sensitive_env_json(output);

        self.with_mutation(|| {
            Ok((
                (),
                OrbitEvent::ToolExecuted {
                    name: name.to_string(),
                },
            ))
        })?;

        Ok(output)
    }

pub fn run_tool_dry_run(&self, name: &str, input: &Value) -> Result<DryRunResult, OrbitError> {
        self.check_tool_enabled(name)?;

        let schema = self
            .tool_registry()
            .get_schema(name)
            .ok_or_else(|| OrbitError::ToolNotFound(name.to_string()))?;

        let mut tool_context = ToolContext {
            cwd: std::env::current_dir()
                .ok()
                .map(|cwd| cwd.to_string_lossy().into_owned()),
            ..Default::default()
        };
        let task_id = resolve_task_id_from_context(self, &tool_context)?;
        tool_context.workspace_root =
            resolve_workspace_root_from_context(self, task_id.as_deref(), &tool_context)?;

        // Validate required parameters are present
        let mut missing_params = Vec::new();
        if let Some(obj) = input.as_object() {
            for param in &schema.parameters {
                if param.required && !obj.contains_key(&param.name) {
                    missing_params.push(param.name.clone());
                }
            }
        } else if !schema.parameters.is_empty() {
            for param in &schema.parameters {
                if param.required {
                    missing_params.push(param.name.clone());
                }
            }
        }

        Ok(DryRunResult {
            tool_name: name.to_string(),
            policy_allowed: true,
            missing_params,
        })
    }

fn resolve_task_id_from_context(
    runtime: &OrbitRuntime,
    tool_context: &ToolContext,
) -> Result<Option<String>, OrbitError> {
    let Some(cwd) = tool_context.cwd.as_deref() else {
        return Ok(None);
    };
    let canonical_cwd = match Path::new(cwd).canonicalize() {
        Ok(path) => path,
        Err(_) => PathBuf::from(cwd),
    };
    let canonical_repo_root = canonical_repo_root(runtime);

    let tasks = runtime.stores().tasks().list()?;
    Ok(tasks
        .into_iter()
        .filter_map(|task| {
            let workspace =
                validated_task_workspace(&canonical_repo_root, task.workspace_path.as_deref()?)?;
            task_workspace_matches(&workspace, &canonical_cwd).then_some((task.id, workspace))
        })
        .max_by_key(|(_, workspace)| workspace.to_string_lossy().len())
        .map(|(task_id, _)| task_id))
}

fn resolve_workspace_root_from_context(
    runtime: &OrbitRuntime,
    task_id: Option<&str>,
    _tool_context: &ToolContext,
) -> Result<Option<PathBuf>, OrbitError> {
    if let Some(task_id) = task_id
        && let Some(workspace_root) = resolve_task_workspace_root(runtime, task_id)
    {
        return Ok(Some(workspace_root));
    }
    Ok(Some(canonical_repo_root(runtime)))
}

fn run_deterministic(
        &self,
        action: &str,
        config: &Value,
        input: &Value,
        tool_context: ToolContext,
    ) -> Result<Value, DispatchError> {
        match action {
            "orbit_tool_call" => {
                // The `config` block shape (see deterministic_reference.yaml):
                //   config: { tool_name: <name>, args: <object> }
                // Input overrides config when both are present.
                let tool_name = input
                    .get("tool_name")
                    .or_else(|| config.get("tool_name"))
                    .and_then(Value::as_str)
                    .ok_or_else(|| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: "missing `tool_name` in config or input".to_string(),
                    })?;
                let args = input
                    .get("args")
                    .or_else(|| config.get("args"))
                    .cloned()
                    .unwrap_or(Value::Null);

                self.run_tool_with_context_and_role(tool_name, args, Role::Admin, tool_context)
                    .map_err(|err| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: format!("{err}"),
                    })
            }
            "git_merge" | "git_push" | "pr_open" | "update_task" | "worktree_setup" => {
                execute_deterministic_action(
                    self,
                    action,
                    input,
                    false,
                    &HashMap::new(),
                    Option::<&StateExecutionContext>::None,
                )
                .map_err(|err| DispatchError::DeterministicActionFailed {
                    action: action.to_string(),
                    message: format!("{err}"),
                })
            }
            // Phase 4 stub handlers. Real git/API logic lands in a follow-up
            // task once the per-asset migration ports the rest of the
            // pipeline dependencies (worktree_setup, pr_open, pr_merge, …).
            // Returning a structured result keeps the activities dispatchable
            // so the §7 `activity.started` / `activity.finished` envelope is
            // emitted end-to-end — an operator running the pipeline today
            // sees the intent even while the implementation is stubbed.
            "promote_agent_main" => {
                let target = input
                    .get("target_branch")
                    .and_then(Value::as_str)
                    .unwrap_or("main");
                let source = input
                    .get("source_branch")
                    .and_then(Value::as_str)
                    .unwrap_or("agent-main");
                Ok(serde_json::json!({
                    "promoted": false,
                    "target_sha": null,
                    "skipped_reason":
                        format!("stub: real promotion from `{source}` to `{target}` lands in a follow-up"),
                }))
            }
            "revert_on_red" => {
                let sha = input
                    .get("commit_sha")
                    .and_then(Value::as_str)
                    .unwrap_or("");
                Ok(serde_json::json!({
                    "reverted": false,
                    "revert_sha": null,
                    "follow_up_issue": null,
                    "skipped_reason":
                        format!("stub: real revert of `{sha}` lands in a follow-up"),
                }))
            }
            "context_conflict_check" => {
                let task_ids = parse_task_ids(input).map_err(|error| {
                    DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: error.to_string(),
                    }
                })?;
                let requested_files = requested_task_files(self, &task_ids).map_err(|error| {
                    DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: error.to_string(),
                    }
                })?;
                let task_conflicts = task_lock_conflicts(self, &task_ids, &requested_files)
                    .map_err(|error| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: error.to_string(),
                    })?;
                let reservation_check = self
                    .stores()
                    .task_reservations()
                    .check(orbit_store::TaskReservationCheckParams {
                        workspace_orbit_dir: workspace_orbit_dir(self),
                        requested_files,
                    })
                    .map_err(|error| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: error.to_string(),
                    })?;
                emit_expired_reservation_events(self, &reservation_check.expired_reservations)
                    .map_err(|error| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: error.to_string(),
                    })?;
                let conflicts =
                    merge_task_lock_conflicts(task_conflicts, reservation_check.conflicts);
                Ok(serde_json::json!({
                    "clear": conflicts.is_empty(),
                    "conflicts": conflicts,
                }))
            }
            "sleep" => {
                let seconds = input
                    .get("seconds")
                    .and_then(Value::as_f64)
                    .ok_or_else(|| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: "missing `seconds`".to_string(),
                    })?;
                if !(0.0..=3600.0).contains(&seconds) {
                    return Err(DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: "`seconds` must be between 0 and 3600".to_string(),
                    });
                }
                let started_at = Instant::now();
                std::thread::sleep(Duration::from_secs_f64(seconds));
                Ok(serde_json::json!({
                    "slept_seconds": started_at.elapsed().as_secs_f64(),
                }))
            }
            // Materialize the workspace backlog for `dispatch_agent`.
            // Filters `status: backlog`, excludes `type: friction`
            // (per CLAUDE.md: friction is reserved for agent self-reports,
            // not shippable work), and in automatic mode drops any backlog
            // task group whose context overlaps files already held by
            // `in-progress`/`review` tasks. Sorts critical → high → medium →
            // low then by `created_at` ascending so older high-priority work
            // ships first. Caps at `max_tasks` (default 50).
            "list_backlog_tasks" => {
                let max_tasks = input
                    .get("max_tasks")
                    .and_then(Value::as_u64)
                    .unwrap_or(50)
                    .min(500) as usize;
                let explicit_task_ids: Vec<String> = input
                    .get("task_ids")
                    .and_then(Value::as_array)
                    .map(|arr| {
                        arr.iter()
                            .filter_map(|v| v.as_str().map(ToOwned::to_owned))
                            .collect()
                    })
                    .unwrap_or_default();
                let mut tasks = if explicit_task_ids.is_empty() {
                    let all_tasks = self.stores().tasks().list().map_err(|err| {
                        DispatchError::DeterministicActionFailed {
                            action: action.to_string(),
                            message: format!("list tasks: {err}"),
                        }
                    })?;
                    let task_lookup: BTreeMap<String, Task> = all_tasks
                        .iter()
                        .cloned()
                        .map(|task| (task.id.clone(), task))
                        .collect();
                    let locked_files = active_task_lock_files(task_lookup.values());
                    let mut backlog: Vec<Task> = all_tasks
                        .into_iter()
                        .filter(|task| {
                            task.status == TaskStatus::Backlog && !task.task_type.is_friction()
                        })
                        .collect();
                    backlog.sort_by(|a, b| {
                        let rank = |p: orbit_common::types::TaskPriority| match p {
                            orbit_common::types::TaskPriority::Critical => 0,
                            orbit_common::types::TaskPriority::High => 1,
                            orbit_common::types::TaskPriority::Medium => 2,
                            orbit_common::types::TaskPriority::Low => 3,
                        };
                        rank(a.priority)
                            .cmp(&rank(b.priority))
                            .then(a.created_at.cmp(&b.created_at))
                    });
                    if !locked_files.is_empty() {
                        let tainted_roots: BTreeSet<String> = backlog
                            .iter()
                            .filter(|task| task_overlaps_locked_files(task, &locked_files))
                            .map(|task| task_root_id(task, &task_lookup))
                            .collect();
                        if !tainted_roots.is_empty() {
                            backlog.retain(|task| {
                                !tainted_roots.contains(&task_root_id(task, &task_lookup))
                            });
                        }
                    }
                    backlog
                } else {
                    explicit_task_ids
                        .iter()
                        .map(|task_id| {
                            self.get_task(task_id).map_err(|err| {
                                DispatchError::DeterministicActionFailed {
                                    action: action.to_string(),
                                    message: format!("load task {task_id}: {err}"),
                                }
                            })
                        })
                        .collect::<Result<Vec<_>, _>>()?
                };
                tasks.truncate(max_tasks);
                let ids: Vec<String> = tasks.iter().map(|t| t.id.clone()).collect();
                let task_objs: Vec<Value> = tasks
                    .iter()
                    .map(|t| {
                        serde_json::json!({
                            "id": t.id,
                            "title": t.title,
                            "type": t.task_type.to_string(),
                            "priority": t.priority.to_string(),
                            "context_files": t.context_files,
                            "parent_id": t.parent_id,
                        })
                    })
                    .collect();
                Ok(serde_json::json!({
                    "task_count": task_objs.len(),
                    "task_ids": ids,
                    "tasks": task_objs,
                }))
            }
            // Materialize an epic's working set for the orchestrator:
            // the epic task itself plus non-terminal subtasks
            // (`parent_id == epic_task_id` and status ∉ {done, archived}).
            // Full descriptions ride along because the orchestrator
            // reasons about dependency ordering from prose.
            "load_epic" => {
                let epic_id = input
                    .get("epic_task_id")
                    .and_then(Value::as_str)
                    .ok_or_else(|| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: "missing `epic_task_id`".to_string(),
                    })?;
                let epic = self.get_task(epic_id).map_err(|err| {
                    DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: format!("load epic {epic_id}: {err}"),
                    }
                })?;
                if epic.task_type != TaskType::Epic {
                    return Err(DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: format!(
                            "task `{epic_id}` has type `{}`; expected `epic`",
                            epic.task_type
                        ),
                    });
                }
                let subtasks = self
                    .list_tasks_filtered(None, None, Some(epic_id), None)
                    .map_err(|err| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: format!("list subtasks of {epic_id}: {err}"),
                    })?;
                let subtask_payload: Vec<Value> = subtasks
                    .iter()
                    .filter(|t| !matches!(t.status, TaskStatus::Done | TaskStatus::Archived))
                    .map(|t| {
                        serde_json::json!({
                            "id": t.id,
                            "title": t.title,
                            "description": t.description,
                            "type": t.task_type.to_string(),
                            "status": t.status.to_string(),
                            "context_files": t.context_files,
                        })
                    })
                    .collect();
                Ok(serde_json::json!({
                    "epic": {
                        "id": epic.id,
                        "title": epic.title,
                        "description": epic.description,
                        "type": epic.task_type.to_string(),
                        "status": epic.status.to_string(),
                    },
                    "subtasks": subtask_payload,
                }))
            }
            // Fold the orchestrator's final state snapshot into counters
            // + a human-readable one-liner. Pure aggregation — the
            // decision history already lives in `orbit.state` per the
            // role prompt.
            "summarize_epic" => {
                let state = input.get("state").cloned().unwrap_or(Value::Null);
                let subtasks_map = state
                    .get("subtasks")
                    .and_then(Value::as_object)
                    .cloned()
                    .unwrap_or_default();
                let mut done = 0u64;
                let mut failed = 0u64;
                let mut blocked = 0u64;
                let mut in_flight = 0u64;
                let mut unfinished_ids: Vec<String> = Vec::new();
                for (id, entry) in subtasks_map.iter() {
                    let entry_state = entry
                        .get("state")
                        .and_then(Value::as_str)
                        .unwrap_or("unknown");
                    match entry_state {
                        "done" => done += 1,
                        "blocked" => {
                            blocked += 1;
                            unfinished_ids.push(id.clone());
                        }
                        "failed" => {
                            failed += 1;
                            unfinished_ids.push(id.clone());
                        }
                        "in_flight" | "pending" => {
                            in_flight += 1;
                            unfinished_ids.push(id.clone());
                        }
                        _ => {
                            unfinished_ids.push(id.clone());
                        }
                    }
                }
                let total = subtasks_map.len() as u64;
                let message = if total == 0 {
                    "epic had no subtasks".to_string()
                } else if unfinished_ids.is_empty() {
                    format!("all {total} subtasks done")
                } else {
                    format!(
                        "{done}/{total} done; {failed} failed, {blocked} blocked, \
                         {in_flight} in flight/pending"
                    )
                };
                Ok(serde_json::json!({
                    "total": total,
                    "done": done,
                    "failed": failed,
                    "blocked": blocked,
                    "in_flight": in_flight,
                    "unfinished_ids": unfinished_ids,
                    "message": message,
                }))
            }
            // Guard the `dispatch_agent`'s bundle output before fan_out.
            // Rejects duplicated task_ids, unknown ids, and oversize
            // bundles with a structured error so a misgrouped backlog
            // never silently dispatches.
            "validate_bundles" => {
                let bundles_raw = input
                    .get("bundles")
                    .and_then(Value::as_array)
                    .cloned()
                    .ok_or_else(|| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: "`bundles` must be an array".to_string(),
                    })?;
                let max_bundle_size = input
                    .get("max_bundle_size")
                    .and_then(Value::as_u64)
                    .unwrap_or(5) as usize;
                let known: std::collections::BTreeSet<String> = input
                    .get("known_task_ids")
                    .and_then(Value::as_array)
                    .map(|arr| {
                        arr.iter()
                            .filter_map(|v| v.as_str().map(ToOwned::to_owned))
                            .collect()
                    })
                    .unwrap_or_default();

                let mut seen: std::collections::BTreeSet<String> =
                    std::collections::BTreeSet::new();
                let mut violations: Vec<String> = Vec::new();
                let mut bundles: Vec<Vec<String>> = Vec::with_capacity(bundles_raw.len());
                for (idx, bundle) in bundles_raw.iter().enumerate() {
                    let items = bundle.as_array().ok_or_else(|| {
                        DispatchError::DeterministicActionFailed {
                            action: action.to_string(),
                            message: format!("bundle[{idx}] is not an array"),
                        }
                    })?;
                    if items.len() > max_bundle_size {
                        violations.push(format!(
                            "bundle[{idx}] size {} exceeds max_bundle_size {}",
                            items.len(),
                            max_bundle_size
                        ));
                    }
                    let mut bundle_ids: Vec<String> = Vec::with_capacity(items.len());
                    for item in items {
                        let id = item.as_str().ok_or_else(|| {
                            DispatchError::DeterministicActionFailed {
                                action: action.to_string(),
                                message: format!("bundle[{idx}] contains a non-string task_id"),
                            }
                        })?;
                        if !known.is_empty() && !known.contains(id) {
                            violations
                                .push(format!("bundle[{idx}] references unknown task_id {id}"));
                        }
                        if !seen.insert(id.to_string()) {
                            violations
                                .push(format!("task_id {id} appears in more than one bundle"));
                        }
                        bundle_ids.push(id.to_string());
                    }
                    bundles.push(bundle_ids);
                }
                if !violations.is_empty() {
                    return Err(DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: format!("invalid bundles: {}", violations.join("; ")),
                    });
                }
                Ok(serde_json::json!({
                    "bundles": bundles,
                    "bundle_count": bundles.len(),
                }))
            }
            // Thin passthrough over `orbit.task.locks.reserve`. Exists as a
            // dedicated action (rather than a `orbit_tool_call` config) so a
            // workflow inside a `loop:` with `break_when:` can reference
            // `steps.<id>.output.reserved` directly without leaking the
            // generic `{tool_name, args}` envelope into the activity's
            // input_schema.
            "reserve_locks" => self
                .run_tool_with_context_and_role(
                    "orbit.task.locks.reserve",
                    input.clone(),
                    Role::Admin,
                    tool_context,
                )
                .map_err(|err| DispatchError::DeterministicActionFailed {
                    action: action.to_string(),
                    message: format!("{err}"),
                }),
            // Submit a child v2 Job and block on its terminal state.
            // Chains `orbit.pipeline.invoke` + `orbit.pipeline.wait` so
            // workflows can model "dispatch and join" as a single step
            // with `{status, run_id, pipeline?, error?}` output.
            "invoke_and_wait" => {
                let job_name = input
                    .get("job_name")
                    .and_then(Value::as_str)
                    .ok_or_else(|| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: "missing `job_name`".to_string(),
                    })?
                    .to_string();
                let run_input = input
                    .get("run_input")
                    .cloned()
                    .unwrap_or_else(|| Value::Object(Default::default()));
                let mut invoke_args = serde_json::Map::new();
                invoke_args.insert("job_name".to_string(), Value::String(job_name.clone()));
                invoke_args.insert("input".to_string(), run_input);
                if let Some(priority) = input.get("priority").cloned() {
                    invoke_args.insert("priority".to_string(), priority);
                }

                let invoke_ctx = tool_context.clone();
                let invoke_output = self
                    .run_tool_with_context_and_role(
                        "orbit.pipeline.invoke",
                        Value::Object(invoke_args),
                        Role::Admin,
                        invoke_ctx,
                    )
                    .map_err(|err| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: format!("pipeline.invoke failed: {err}"),
                    })?;

                let run_id = invoke_output
                    .get("run_id")
                    .and_then(Value::as_str)
                    .ok_or_else(|| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: "pipeline.invoke returned no run_id".to_string(),
                    })?
                    .to_string();

                let mut wait_args = serde_json::Map::new();
                wait_args.insert(
                    "run_ids".to_string(),
                    Value::Array(vec![Value::String(run_id.clone())]),
                );
                if let Some(timeout) = input.get("timeout_seconds").cloned() {
                    wait_args.insert("timeout_seconds".to_string(), timeout);
                }
                if let Some(poll) = input.get("poll_interval_seconds").cloned() {
                    wait_args.insert("poll_interval_seconds".to_string(), poll);
                }

                let wait_output = self
                    .run_tool_with_context_and_role(
                        "orbit.pipeline.wait",
                        Value::Object(wait_args),
                        Role::Admin,
                        tool_context,
                    )
                    .map_err(|err| DispatchError::DeterministicActionFailed {
                        action: action.to_string(),
                        message: format!("pipeline.wait failed: {err}"),
                    })?;

                let first = wait_output
                    .get("results")
                    .and_then(Value::as_array)
                    .and_then(|arr| arr.first())
                    .cloned()
                    .unwrap_or_else(|| {
                        serde_json::json!({
                            "run_id": run_id,
                            "status": "pending",
                        })
                    });
                Ok(first)
            }
            // Post-loop gate signal: the admission window never opened in
            // time. Emits a `gate.starvation` audit event with task_ids and
            // conflicting_files so an epic-orchestrator parent can decide
            // to replan, then fails the Run with a structured error.
            "gate_starvation_fail" => {
                let task_ids_vec: Vec<String> = input
                    .get("task_ids")
                    .and_then(Value::as_array)
                    .map(|arr| {
                        arr.iter()
                            .filter_map(|v| v.as_str().map(ToOwned::to_owned))
                            .collect()
                    })
                    .unwrap_or_default();
                let conflicts = input
                    .get("conflicts")
                    .cloned()
                    .unwrap_or(Value::Array(Vec::new()));
                let max_wait_seconds = input.get("max_wait_seconds").and_then(Value::as_f64);
                let conflicting_files: Vec<String> = conflicts
                    .as_array()
                    .map(|arr| {
                        arr.iter()
                            .filter_map(|entry| {
                                entry
                                    .get("file")
                                    .and_then(Value::as_str)
                                    .map(ToOwned::to_owned)
                            })
                            .collect()
                    })
                    .unwrap_or_default();

                let payload = serde_json::json!({
                    "task_ids": task_ids_vec,
                    "conflicting_files": conflicting_files,
                    "conflicts": conflicts,
                    "max_wait_seconds": max_wait_seconds,
                });

                let execution_id = format!(
                    "audit-gate-starvation-{}",
                    std::time::SystemTime::now()
                        .duration_since(std::time::UNIX_EPOCH)
                        .map(|duration| duration.as_nanos())
                        .unwrap_or(0)
                );
                let working_directory = self.paths().repo_root.to_string_lossy().into_owned();
                self.record_audit_event(&AuditEventInsertParams {
                    execution_id,
                    command: "gate.starvation".to_string(),
                    subcommand: None,
                    tool_name: None,
                    target_type: Some("task_bundle".to_string()),
                    target_id: task_ids_vec.first().cloned(),
                    role: "admin".to_string(),
                    status: AuditEventStatus::Failure,
                    exit_code: 1,
                    duration_ms: 0,
                    working_directory,
                    arguments_json: Some(serde_json::to_string(&payload).map_err(|error| {
                        DispatchError::DeterministicActionFailed {
                            action: action.to_string(),
                            message: format!("serialize gate.starvation payload: {error}"),
                        }
                    })?),
                    stdout_truncated: None,
                    stderr_truncated: None,
                    error_message: Some("gate.starvation".to_string()),
                    host: std::env::var("HOSTNAME").ok(),
                    pid: std::process::id(),
                    session_id: None,
                })
                .map_err(|err| DispatchError::DeterministicActionFailed {
                    action: action.to_string(),
                    message: format!("record gate.starvation audit: {err}"),
                })?;

                Err(DispatchError::DeterministicActionFailed {
                    action: action.to_string(),
                    message: format!(
                        "gate.starvation: admission window never opened for bundle {:?} \
                         (conflicting_files={:?}, max_wait_seconds={:?})",
                        task_ids_vec, conflicting_files, max_wait_seconds
                    ),
                })
            }
            other => Err(DispatchError::DeterministicActionNotRegistered(
                other.to_string(),
            )),
        }
    }

fn tool_context_for_activity(
        &self,
        fs_profile: Option<&str>,
        fs_audit: Option<Arc<dyn FsAuditLogger>>,
    ) -> ToolContext {
        let workspace_root = self
            .paths()
            .repo_root
            .canonicalize()
            .unwrap_or_else(|_| self.paths().repo_root.clone());

        ToolContext {
            cwd: std::env::current_dir()
                .ok()
                .map(|cwd| cwd.to_string_lossy().into_owned()),
            workspace_root: Some(workspace_root),
            policy_engine: Some(Arc::new(self.policy_engine().clone())),
            fs_profile: Some(fs_profile.unwrap_or(UNRESTRICTED_FS_PROFILE).to_string()),
            fs_audit,
            orbit_host: Some(build_orbit_tool_host(self, None)),
            ..Default::default()
        }
    }

pub fn drive_agent_loop_with_tool_context(
    spec: &AgentLoopSpec,
    api_key: Option<&str>,
    run_id: &str,
    audit: Arc<V2AuditWriter>,
    input: &Value,
    tool_ctx: ToolContext,
) -> Result<LoopOutcome, DispatchError> {
    let model = resolve_model(spec);
    let provider = expected_provider();
    let mut session = Session::new(provider, model.clone(), &spec.instruction, None);
    drive_inner(spec, api_key, run_id, audit, &mut session, input, tool_ctx)
}

fn drive_inner(
    spec: &AgentLoopSpec,
    api_key: Option<&str>,
    run_id: &str,
    audit: Arc<V2AuditWriter>,
    session: &mut Session,
    input: &Value,
    tool_ctx: ToolContext,
) -> Result<LoopOutcome, DispatchError> {
    let model = resolve_model(spec);
    let user_prompt = user_prompt_from_input(input)?;

    if replay_active() {
        // Reuse the same ReplayTransport across calls so the cursor advances
        // through the scripted turns. Loop-body steps reuse the Session and
        // need the transport's state to persist too, else every iteration
        // would replay the same first turn.
        let transport = acquire_replay_transport(&model)?;
        run_loop(
            spec,
            run_id,
            audit,
            session,
            &*transport,
            &user_prompt,
            tool_ctx,
        )
    } else {
        let key = api_key.ok_or_else(|| {
            DispatchError::AgentLoopFailed(
                "no provider credential available — host.api_key_for returned an error".to_string(),
            )
        })?;
        if key.is_empty() {
            return Err(DispatchError::AgentLoopFailed(
                "api_key is empty".to_string(),
            ));
        }
        let transport = AnthropicMessagesTransport::new(key.to_string(), model.clone())
            .map_err(|err| DispatchError::AgentLoopFailed(format!("transport: {err}")))?;
        run_loop(
            spec,
            run_id,
            audit,
            session,
            &transport,
            &user_prompt,
            tool_ctx,
        )
    }
}

fn run_loop<T: LoopTransport>(
    spec: &AgentLoopSpec,
    run_id: &str,
    audit: Arc<V2AuditWriter>,
    session: &mut Session,
    transport: &T,
    user_prompt: &str,
    tool_ctx: ToolContext,
) -> Result<LoopOutcome, DispatchError> {
    let mut registry = orbit_tools::ToolRegistry::new();
    registry.register_builtins();

    let cfg = AgentLoopConfig::new_for_run(run_id)
        .with_allowlist(spec.tools.clone())
        .with_advertised_tools(spec.tools.clone())
        .with_max_iterations(spec.max_iterations.max(1))
        .with_max_total_tokens(u64::MAX)
        .with_wall_clock_timeout(Duration::from_secs(spec.wall_clock_timeout_seconds.max(1)));

    let session_id = session.id().to_string();

    let inner = audit.inner_sink();
    let enforced =
        EnforcedAuditSink::new(inner, spec.tools.clone(), audit.clone(), run_id, session_id);

    let res = AgentLoop::run(
        session,
        &cfg,
        transport,
        &registry,
        &tool_ctx,
        &enforced,
        user_prompt,
    );
    match res {
        Ok(outcome) => Ok(outcome),
        // §4.3 classifies denial as non-retryable. Surface structurally so the
        // Phase 3 retry wrapper can skip retry. The §7 `tool.denied` audit
        // event was already emitted by `EnforcedAuditSink` before this point.
        Err(AgentLoopError::PolicyDenied {
            tool_name,
            iteration,
        }) => Err(DispatchError::ToolDenied {
            tool_name,
            iteration,
        }),
        Err(err) => Err(DispatchError::AgentLoopFailed(format!("{err:?}"))),
    }
}

fn verify_checkpoint(
    host: &dyn V2RuntimeHost,
    tool_ctx: &ToolContext,
    workspace_path: &Path,
    checkpoint: &TaskPlanCheckpoint,
) -> Result<VerifierOutcome, DispatchError> {
    for criterion in &checkpoint.success_criteria {
        match criterion {
            orbit_common::types::TaskPlanSuccessCriterion::Command {
                command,
                expect_exit,
            } => {
                let result = run_workspace_command(host, tool_ctx, workspace_path, command)?;
                let actual = result.exit_code.unwrap_or(-1);
                if actual != *expect_exit {
                    let detail = truncate_for_failure_report(format!(
                        "command `{}` exited {} (expected {})\nstdout:\n{}\nstderr:\n{}",
                        command, actual, expect_exit, result.stdout, result.stderr
                    ));
                    return Ok(VerifierOutcome {
                        failure_report: Some(FailureReport {
                            what_tried: format!(
                                "verified command criterion for checkpoint `{}`",
                                checkpoint.id
                            ),
                            what_happened: detail,
                            next_attempt_plan:
                                "Fix the failing verifier condition before emitting checkpoint_success again."
                                    .to_string(),
                        }),
                    });
                }
            }
            orbit_common::types::TaskPlanSuccessCriterion::FileExists { path } => {
                let resolved = resolve_checkpoint_path(workspace_path, path);
                if !resolved.exists() {
                    return Ok(VerifierOutcome {
                        failure_report: Some(FailureReport {
                            what_tried: format!(
                                "verified file_exists criterion for checkpoint `{}`",
                                checkpoint.id
                            ),
                            what_happened: format!("required file `{}` does not exist", path),
                            next_attempt_plan:
                                "Create the expected file before emitting checkpoint_success again."
                                    .to_string(),
                        }),
                    });
                }
            }
            orbit_common::types::TaskPlanSuccessCriterion::FileContains { path, pattern } => {
                let resolved = resolve_checkpoint_path(workspace_path, path);
                let contents = fs::read_to_string(&resolved).map_err(|error| {
                    DispatchError::GroundhogFailed(format!(
                        "read verifier file {}: {error}",
                        resolved.display()
                    ))
                })?;
                if !contents.contains(pattern) {
                    return Ok(VerifierOutcome {
                        failure_report: Some(FailureReport {
                            what_tried: format!(
                                "verified file_contains criterion for checkpoint `{}`",
                                checkpoint.id
                            ),
                            what_happened: format!(
                                "file `{}` does not contain required pattern `{}`",
                                path, pattern
                            ),
                            next_attempt_plan:
                                "Update the file so the required pattern is present before emitting checkpoint_success again."
                                    .to_string(),
                        }),
                    });
                }
            }
            orbit_common::types::TaskPlanSuccessCriterion::Semantic { .. } => {}
        }
    }

    Ok(VerifierOutcome {
        failure_report: None,
    })
}

fn run_workspace_command(
    host: &dyn V2RuntimeHost,
    tool_ctx: &ToolContext,
    workspace_path: &Path,
    command: &str,
) -> Result<ExecutionResult, DispatchError> {
    let cwd = shell_single_quote(&workspace_path.display().to_string());
    let script = format!("cd {cwd} && {command}");
    let value = host
        .run_deterministic(
            "orbit_tool_call",
            &Value::Null,
            &json!({
                "tool_name": "proc.spawn",
                "args": {
                    "program": "sh",
                    "args": ["-lc", script],
                    "timeout_ms": DEFAULT_COMMAND_TIMEOUT_MS
                }
            }),
            tool_ctx.clone(),
        )
        .map_err(|error| {
            DispatchError::GroundhogFailed(format!("proc.spawn verifier call: {error}"))
        })?;
    serde_json::from_value(value).map_err(|error| {
        DispatchError::GroundhogFailed(format!("parse proc.spawn result: {error}"))
    })
}

fn persist_runner_artifacts(
    host: &dyn V2RuntimeHost,
    tool_ctx: &ToolContext,
    task_id: &str,
    chronicle: &Chronicle,
    state: &GroundhogRunnerState,
    status: Option<&str>,
    comment: Option<String>,
) -> Result<(), DispatchError> {
    let chronicle_json = serde_json::to_string_pretty(chronicle)
        .map_err(|error| DispatchError::GroundhogFailed(format!("serialize chronicle: {error}")))?;
    let state_json = serde_json::to_string_pretty(state)
        .map_err(|error| DispatchError::GroundhogFailed(format!("serialize state: {error}")))?;
    let artifacts = vec![
        TaskArtifact {
            path: CHRONICLE_ARTIFACT_PATH.to_string(),
            content: chronicle_json,
        },
        TaskArtifact {
            path: STATE_ARTIFACT_PATH.to_string(),
            content: state_json,
        },
    ];

    let mut args = json!({
        "id": task_id,
        "artifacts": artifacts
    });
    if let Some(status) = status {
        args["status"] = Value::String(status.to_string());
    }
    if let Some(comment) = comment {
        args["comment"] = Value::String(comment);
    }

    let _ = host
        .run_deterministic(
            "orbit_tool_call",
            &Value::Null,
            &json!({
                "tool_name": "orbit.task.update",
                "args": args
            }),
            tool_ctx.clone(),
        )
        .map_err(|error| {
            DispatchError::GroundhogFailed(format!("persist groundhog artifacts: {error}"))
        })?;
    Ok(())
}

fn load_task(
    host: &dyn V2RuntimeHost,
    tool_ctx: &ToolContext,
    task_id: &str,
) -> Result<GroundhogTaskSnapshot, DispatchError> {
    let value = host
        .run_deterministic(
            "orbit_tool_call",
            &Value::Null,
            &json!({
                "tool_name": "orbit.task.show",
                "args": { "id": task_id }
            }),
            tool_ctx.clone(),
        )
        .map_err(|error| {
            DispatchError::GroundhogFailed(format!("load task `{task_id}`: {error}"))
        })?;
    serde_json::from_value(value)
        .map_err(|error| DispatchError::GroundhogFailed(format!("parse task `{task_id}`: {error}")))
}

fn load_task_artifacts(
    host: &dyn V2RuntimeHost,
    tool_ctx: &ToolContext,
    task_id: &str,
) -> Result<Vec<TaskArtifact>, DispatchError> {
    let value = host
        .run_deterministic(
            "orbit_tool_call",
            &Value::Null,
            &json!({
                "tool_name": "orbit.task.show",
                "args": { "id": task_id, "field": "artifacts" }
            }),
            tool_ctx.clone(),
        )
        .map_err(|error| {
            DispatchError::GroundhogFailed(format!("load artifacts for task `{task_id}`: {error}"))
        })?;
    serde_json::from_value(value).map_err(|error| {
        DispatchError::GroundhogFailed(format!("parse artifacts for task `{task_id}`: {error}"))
    })
}

fn load_chronicle(
    host: &dyn V2RuntimeHost,
    tool_ctx: &ToolContext,
    task_id: &str,
) -> Result<Chronicle, DispatchError> {
    let artifacts = load_task_artifacts(host, tool_ctx, task_id)?;
    let Some(artifact) = artifacts
        .into_iter()
        .find(|artifact| artifact.path == CHRONICLE_ARTIFACT_PATH)
    else {
        return Ok(Chronicle::new(
            task_id.to_string(),
            format!("{task_id}:plan"),
        ));
    };

    serde_json::from_str(&artifact.content).map_err(|error| {
        DispatchError::GroundhogFailed(format!(
            "parse chronicle artifact for task `{task_id}`: {error}"
        ))
    })
}

fn load_state(
    host: &dyn V2RuntimeHost,
    tool_ctx: &ToolContext,
    task_id: &str,
) -> Result<GroundhogRunnerState, DispatchError> {
    let artifacts = load_task_artifacts(host, tool_ctx, task_id)?;
    let Some(artifact) = artifacts
        .into_iter()
        .find(|artifact| artifact.path == STATE_ARTIFACT_PATH)
    else {
        return Ok(GroundhogRunnerState::default());
    };

    serde_json::from_str(&artifact.content).map_err(|error| {
        DispatchError::GroundhogFailed(format!(
            "parse runner state artifact for task `{task_id}`: {error}"
        ))
    })
}

fn resolve_workspace_path(
    input: &Value,
    tool_ctx: &ToolContext,
    task_workspace_path: &Option<String>,
) -> Result<PathBuf, DispatchError> {
    let selected = input
        .get("workspace_path")
        .and_then(Value::as_str)
        .map(ToString::to_string)
        .or_else(|| task_workspace_path.clone())
        .or_else(|| {
            tool_ctx
                .workspace_root
                .as_ref()
                .map(|path| path.to_string_lossy().into_owned())
        })
        .ok_or_else(|| {
            DispatchError::GroundhogFailed(
                "groundhog activity requires a workspace path or workspace_root".to_string(),
            )
        })?;
    Ok(PathBuf::from(selected))
}

fn execute(&self, _host: ExecutorHost<'_>, execution: &ExecutionContext) -> AttemptOutcome {
        let input = &execution.input;
        let tool_name = match input.get("tool_name").and_then(Value::as_str) {
            Some(s) => s.to_string(),
            None => {
                return AttemptOutcome::failed(
                    ACTIVITY_EXECUTION_FAILED,
                    "orbit_tool_call: missing `tool_name`".to_string(),
                );
            }
        };
        let args = input.get("args").cloned().unwrap_or(Value::Null);

        // Phase 2: record the tool-call request structurally without actually
        // dispatching into ToolRegistry (which requires wiring a full
        // ToolContext from the engine). The structural output is sufficient
        // for reference-asset validation. Phase 4 wires the real dispatch.
        let output = json!({
            "tool_name": tool_name,
            "args": args,
            "status": "structural_dispatch",
        });
        AttemptOutcome::success(0, 0, output)
    }

fn run_tool_with_context_and_role(
        &self,
        name: &str,
        input: Value,
        role: Role,
        tool_context: ToolContext,
    ) -> Result<Value, OrbitError> {
        self.runtime
            .run_tool_with_context_and_role(name, input, role, tool_context)
    }

pub(super) fn cleanup_stale_planning_duel_artifacts<H: RuntimeHost + TaskHost + ?Sized>(
    host: &H,
    task_id: &str,
) -> Result<(), OrbitError> {
    let stale_artifacts = host
        .get_task_artifacts(task_id)?
        .into_iter()
        .filter(|artifact| artifact.path.starts_with(PLANNING_DUEL_ARTIFACT_PREFIX))
        .collect::<Vec<_>>();
    if stale_artifacts.is_empty() {
        return Ok(());
    }

    let tasks_root = host.data_root().join(TASKS_DIR_NAME);
    let task_dir = find_task_dir(&tasks_root, task_id)?.ok_or_else(|| {
        OrbitError::Execution(format!(
            "could not locate task directory for '{task_id}' while cleaning stale planning duel artifacts"
        ))
    })?;
    let artifacts_root = task_dir.join(TASK_ARTIFACTS_DIR_NAME);
    let tool_context = ToolContext {
        cwd: Some(host.data_root().display().to_string()),
        allowed_tools: vec!["fs.delete".to_string()],
        workspace_root: Some(host.data_root().to_path_buf()),
        ..ToolContext::default()
    };

    for artifact in stale_artifacts {
        let artifact_path = artifacts_root.join(&artifact.path);
        if !artifact_path.exists() {
            return Err(OrbitError::Execution(format!(
                "stale planning duel artifact '{}' is missing on disk for task '{}'",
                artifact.path, task_id
            )));
        }
        let _ = host.run_tool_with_context_and_role(
            "fs.delete",
            json!({ "path": artifact_path.display().to_string() }),
            Role::Admin,
            tool_context.clone(),
        )?;
    }

    Ok(())
}

pub(super) fn merge_batch_pr<H: RuntimeHost + TaskHost + ?Sized>(
    host: &H,
    input: &Value,
) -> Result<Value, OrbitError> {
    let batch_id = required_batch_id(input, "merge_batch_pr")?;

    let batch_tasks = host.list_tasks_filtered(None, None, None, Some(batch_id))?;
    if batch_tasks.is_empty() {
        return Err(OrbitError::InvalidInput(format!(
            "merge_batch_pr: no tasks found for batch_id '{batch_id}'"
        )));
    }

    // Find pr_number from the first task that has one
    let pr_number = batch_tasks
        .iter()
        .find_map(|t| t.pr_number.as_deref())
        .ok_or_else(|| {
            OrbitError::InvalidInput("merge_batch_pr: no task in batch has a pr_number".to_string())
        })?
        .to_string();

    let workspace_path = resolve_batch_workspace_path(host, input, batch_id)?;

    // Get the current branch from the workspace
    let head = git_output(&workspace_path, &["rev-parse", "--abbrev-ref", "HEAD"])?;
    let head = head.trim().to_string();
    let base = input_string_field(input, "base").unwrap_or_else(|| "main".to_string());

    // Check that ALL tasks have APPROVED pr_status
    for task in &batch_tasks {
        let pr_status_raw = task.pr_status.as_deref().unwrap_or("none");
        let review_decision = super::review::normalize_review_decision(pr_status_raw);
        if review_decision != "APPROVED" {
            return Err(OrbitError::Execution(format!(
                "task '{}' is not approved (pr_status={pr_status_raw})",
                task.id
            )));
        }
    }

    // Check that ALL tasks are in Review or Done status
    for task in &batch_tasks {
        if !matches!(task.status, TaskStatus::Review | TaskStatus::Done) {
            return Err(OrbitError::Execution(format!(
                "task '{}' must be in Review or Done before merge_batch_pr; current status is {}",
                task.id, task.status
            )));
        }
    }

    ensure_branch_fresh_against_base(&workspace_path, &head, &base)?;

    let tool_context = ToolContext {
        cwd: Some(workspace_path.to_string_lossy().to_string()),
        allowed_tools: vec![],
        ..Default::default()
    };
    host.run_tool_with_context_and_role(
        "github.pr.merge",
        json!({
            "pr": pr_number,
            "strategy": "squash",
            // Do not pass --delete-branch to `gh pr merge` because the local
            // branch is still attached to the shared worktree and `gh` would
            // fail trying to delete it.  We delete the remote branch separately
            // below, tolerating errors (the repo may auto-delete branches after
            // merge).
            "delete_branch": false,
        }),
        Role::Admin,
        tool_context,
    )?;

    // Best-effort remote branch cleanup.  Some repos have GitHub's
    // "Automatically delete head branches" enabled, so the remote ref may
    // already be gone — ignore errors.
    let _ =
        super::git::git_command_success(&workspace_path, &["push", "origin", "--delete", &head]);

    let batch_requires_revision = batch_tasks.iter().any(task_required_revision);
    let batch_author = batch_tasks.iter().find_map(|task| {
        normalize_optional_attribution_label(
            task.implemented_by
                .as_deref()
                .or(task.model.as_deref())
                .or(task.created_by.as_deref()),
            task.model.as_deref(),
        )
    });

    // Advance ALL batch tasks to Done status
    for task in &batch_tasks {
        host.apply_task_automation_update(
            &task.id,
            TaskAutomationUpdate {
                status: if task.status == TaskStatus::Review {
                    Some(TaskStatus::Done)
                } else {
                    None
                },
                pr_number: Some(pr_number.clone()),
                ..TaskAutomationUpdate::default()
            },
        )?;
    }

    if host.scoring_enabled()
        && let Some(model) = batch_author
    {
        let _ = if batch_requires_revision {
            pr_scoreboard::record_pr_count_with_revision(host.scoreboard_dir(), &model)
        } else {
            pr_scoreboard::record_pr_count_without_revision(host.scoreboard_dir(), &model)
        };
    }

    Ok(json!({ "merged": true }))
}

pub(super) fn open_batch_pr<H: RuntimeHost + TaskHost + ?Sized>(
    host: &H,
    input: &Value,
) -> Result<Value, OrbitError> {
    if input.get("failed").and_then(Value::as_u64).unwrap_or(0) > 0 {
        return Err(OrbitError::Execution(
            "open_batch_pr: cannot open a batch PR while worker failures remain".to_string(),
        ));
    }

    let workspace_path_str = required_input_string(input, "workspace_path")?;
    let workspace_path = canonicalize_existing_dir(workspace_path_str, "workspace_path")?;

    let batch_id = required_batch_id(input, "open_batch_pr")?;

    let completed_task_ids = match completed_task_ids_from_input(input) {
        Some(task_ids) => task_ids,
        None => host
            .list_tasks_filtered(None, None, None, Some(batch_id))?
            .into_iter()
            .map(|task| task.id)
            .collect(),
    };

    if completed_task_ids.is_empty() {
        return Err(OrbitError::InvalidInput(format!(
            "open_batch_pr: no tasks found for batch_id '{batch_id}'"
        )));
    }

    let head = git_output(&workspace_path, &["rev-parse", "--abbrev-ref", "HEAD"])?;
    let head = head.trim().to_string();
    let base = input_string_field(input, "base").unwrap_or_else(|| "main".to_string());

    let rebase_outcome = ensure_branch_rebased_onto_base(&workspace_path, &head, &base)?;
    let freshness = rebase_outcome.freshness;
    let branch_was_rebased = rebase_outcome.rebased;

    let diff_output = git_output(
        &workspace_path,
        &["diff", "--name-only", &format!("{base}...{head}")],
    )
    .unwrap_or_default();
    let changed_files: Vec<&str> = diff_output
        .lines()
        .filter(|line| !line.is_empty())
        .collect();

    let mut completed_tasks = Vec::new();
    for task_id in &completed_task_ids {
        let task = host.get_task(task_id)?;
        if task.batch_id.as_deref() != Some(batch_id) {
            return Err(OrbitError::Execution(format!(
                "open_batch_pr: task '{}' no longer belongs to batch '{}'",
                task.id, batch_id
            )));
        }
        ensure_task_can_enter_pr_review(&task)?;
        completed_tasks.push(task);
    }
    let title = input_string_field(input, "title")
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| default_pr_title(&completed_tasks));
    let body = input_string_field(input, "body")
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| build_batch_pr_body(&completed_tasks, &freshness, &changed_files));

    let tool_context = ToolContext {
        cwd: Some(workspace_path.to_string_lossy().to_string()),
        allowed_tools: vec![],
        ..Default::default()
    };

    host.run_tool_with_context_and_role(
        "git.push",
        json!({
            "repo_root": workspace_path.to_string_lossy().to_string(),
            "branch": head,
            "force_with_lease": branch_was_rebased,
        }),
        Role::Admin,
        tool_context.clone(),
    )?;

    let pr_create = host.run_tool_with_context_and_role(
        "github.pr.create",
        json!({
            "title": title,
            "body": body,
            "base": base,
            "head": head,
        }),
        Role::Admin,
        tool_context.clone(),
    )?;
    let pr_url = pr_create
        .get("url")
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| {
            OrbitError::Execution("github.pr.create did not return a PR url".to_string())
        })?
        .to_string();
    let pr_view = host.run_tool_with_context_and_role(
        "github.pr.view",
        json!({ "pr": pr_url }),
        Role::Admin,
        tool_context,
    )?;
    let pr_number = pr_view
        .get("pull_request")
        .and_then(|value| value.get("number"))
        .and_then(json_number_to_string)
        .ok_or_else(|| {
            OrbitError::Execution("github.pr.view did not return a PR number".to_string())
        })?;

    for task_id in &completed_task_ids {
        host.apply_task_automation_update(
            task_id,
            TaskAutomationUpdate {
                status: Some(TaskStatus::Review),
                pr_number: Some(pr_number.clone()),
                ..TaskAutomationUpdate::default()
            },
        )?;
    }

    Ok(json!({}))
}

