fn execute(&self, ctx: &ToolContext, input: Value) -> Result<Value, OrbitError> {
        let selector_str = super::required_string(&input, &["selector"], "selector")?;
        let limit = input
            .get("limit")
            .and_then(Value::as_u64)
            .unwrap_or(DEFAULT_LIMIT as u64) as usize;
        let include_simple_name = input
            .get("include_simple_name")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let include = RefInclude::parse(&input)?;
        let per_file_limit = input
            .get("per_file_limit")
            .and_then(Value::as_u64)
            .unwrap_or(DEFAULT_PER_FILE_LIMIT as u64) as usize;

        let selector: Selector = selector_str
            .parse()
            .map_err(|e| OrbitError::InvalidInput(format!("{e}")))?;

        // Extract symbol name from selector
        let search_terms = match &selector {
            Selector::Symbol { symbol, .. } => {
                let mut search_terms = vec![symbol.clone()];
                if let Some(simple_name) = symbol.rsplit("::").next()
                    && include_simple_name
                    && simple_name != symbol
                {
                    search_terms.push(simple_name.to_string());
                }
                search_terms
            }
            _ => {
                return Err(OrbitError::InvalidInput(
                    "refs requires a symbol selector (e.g. symbol:path#name:kind)".to_string(),
                ));
            }
        };

        // Extract the defining file to exclude self-references
        let knowledge_dir = super::knowledge_write::resolve_knowledge_dir(ctx, &input)?;
        let graph = super::load_graph_for_read(ctx, &input)?;
        let svc = GraphContextService::new(&graph);
        let all_hits = svc.find_references(
            Some(&knowledge_dir),
            &search_terms,
            Some(selector_str.as_str()),
        );
        let mut code_refs = Vec::new();
        let mut doc_refs = Vec::new();
        let mut config_refs = Vec::new();
        let mut remaining = limit;
        let mut file_counts = HashMap::<(RefKind, String), usize>::new();

        for hit in all_hits {
            let kind = classify_ref_kind(&hit.file);
            if !include.includes(kind) {
                continue;
            }

            let count = file_counts.entry((kind, hit.file.clone())).or_default();
            if *count >= per_file_limit {
                continue;
            }
            if remaining == 0 {
                break;
            }

            *count += 1;
            remaining -= 1;

            let value = json!({
                "selector": hit.selector,
                "name": hit.name,
                "file": hit.file,
                "kind": hit.kind,
            });

            match kind {
                RefKind::Code => code_refs.push(value),
                RefKind::Doc => doc_refs.push(value),
                RefKind::Config => config_refs.push(value),
            }
        }

        Ok(json!({
            "code_refs": code_refs,
            "doc_refs": doc_refs,
            "config_refs": config_refs,
        }))
    }

fn execute(&self, ctx: &ToolContext, input: Value) -> Result<Value, OrbitError> {
        let query = super::optional_string(&input, "query")?.unwrap_or_default();
        let node_type = super::optional_string(&input, "type")?;
        let kind_filter = super::optional_string(&input, "kind")?;
        let prefix = super::optional_string(&input, "prefix")?;
        let limit = input
            .get("limit")
            .and_then(Value::as_u64)
            .unwrap_or(DEFAULT_LIMIT as u64) as usize;
        let include_non_code = input
            .get("include_non_code")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let format = super::optional_string(&input, "format")?;
        let use_selectors = format.as_deref() == Some("selectors");
        let use_default_ranking = node_type.is_none() && kind_filter.is_none() && prefix.is_none();

        let graph = super::load_graph_for_read(ctx, &input)?;
        let svc = GraphContextService::new(&graph);

        let type_strs: Vec<&str> = node_type.iter().map(String::as_str).collect();
        let node_types = if type_strs.is_empty() {
            None
        } else {
            Some(type_strs.as_slice())
        };
        let search_limit = if use_default_ranking {
            usize::MAX
        } else {
            limit
        };
        let (service_total, nodes) = svc.search_with_total(
            &query,
            node_types,
            prefix.as_deref(),
            kind_filter.as_deref(),
            search_limit,
        );
        let (total, nodes) = if use_default_ranking {
            let ranked = rank_default_search_results(nodes, include_non_code);
            let total = ranked.len();
            let limited = ranked.into_iter().take(limit).collect::<Vec<_>>();
            (total, limited)
        } else {
            (service_total, nodes)
        };

        if use_selectors {
            let selectors: Vec<String> = nodes.iter().map(|n| svc.selector_for_node(*n)).collect();
            Ok(json!(selectors))
        } else {
            let items: Vec<Value> = nodes
                .into_iter()
                .map(|node| {
                    let kind = match node {
                        GraphNodeRef::Dir(_) => "dir".to_string(),
                        GraphNodeRef::File(_) => "file".to_string(),
                        GraphNodeRef::Leaf(leaf) => leaf.kind.to_string(),
                    };
                    let file = match node {
                        GraphNodeRef::Leaf(leaf) => leaf
                            .base
                            .location
                            .split_once('#')
                            .map(|(path, _)| path.to_string()),
                        GraphNodeRef::File(file) => Some(file.base.location.clone()),
                        GraphNodeRef::Dir(_) => None,
                    };

                    let mut obj = json!({
                        "selector": svc.selector_for_node(node),
                        "name": node.base().name,
                        "kind": kind,
                    });
                    if let Some(file) = file {
                        obj["file"] = json!(file);
                    }
                    obj
                })
                .collect();
            Ok(json!({
                "total": total,
                "results": items,
            }))
        }
    }

fn execute(&self, ctx: &ToolContext, input: Value) -> Result<Value, OrbitError> {
        let selector_str = super::required_string(&input, &["selector"], "selector")?;
        let selector: Selector = selector_str
            .parse()
            .map_err(|e| OrbitError::InvalidInput(format!("{e}")))?;

        let depth = input.get("depth").and_then(Value::as_u64).unwrap_or(2) as usize;
        let max_siblings = input.get("siblings").and_then(Value::as_u64).unwrap_or(3) as usize;
        let max_children = input.get("children").and_then(Value::as_u64).unwrap_or(5) as usize;

        let graph = super::load_graph_for_read(ctx, &input)?;
        let svc = GraphContextService::new(&graph);

        let node = svc
            .resolve_selector(&selector)
            .map_err(|e| OrbitError::InvalidInput(e.to_string()))?;

        let node_ctx = svc
            .bounded_context(node.id(), depth, max_siblings, max_children)
            .map_err(|e| OrbitError::Execution(e.to_string()))?;

        Ok(build_json(&svc, &node_ctx))
    }

