pub trait V2RuntimeHost: Send + Sync {
    /// Dispatch a deterministic action by name. The host looks up `action`
    /// in its registry and returns the action's structured output.
    fn run_deterministic(
        &self,
        action: &str,
        config: &Value,
        input: &Value,
        tool_context: ToolContext,
    ) -> Result<Value, DispatchError>;

    /// Source the API key for a given provider (e.g. `"anthropic"`). Returns
    /// the raw key as a `String` so nothing orbit-agent-shaped bleeds across
    /// the boundary. Implementors typically read from env or config.
    fn api_key_for(&self, provider: &str) -> Result<String, DispatchError>;

    /// Resolve the CLI binary command for a given v2 provider name (§3.1
    /// backend: cli path). Workspace / env overrides live in the host so the
    /// engine's CLI runner stays environment-agnostic. Returning an error is
    /// the structured failure path when a provider has no CLI mapping (e.g.
    /// `openai_compat` which is HTTP-only).
    fn resolve_cli_command(&self, provider: &str) -> Result<String, DispatchError>;

    fn tool_context_for_activity(
        &self,
        fs_profile: Option<&str>,
        fs_audit: Option<Arc<dyn FsAuditLogger>>,
    ) -> ToolContext;
}

pub trait RuntimeHost {
    fn record_event(&self, event: OrbitEvent) -> Result<(), OrbitError>;
    fn repo_root(&self) -> Result<String, OrbitError>;
    fn data_root(&self) -> &Path;
    fn activity_executor_registry(&self) -> &ActivityExecutorRegistry;
    fn run_job_now_with_input_debug(
        &self,
        job_id: &str,
        input: Value,
        debug: bool,
    ) -> Result<JobRunResult, OrbitError>;
    fn validate_activity_target_exists(
        &self,
        target_type: JobTargetType,
        target_id: &str,
    ) -> Result<Activity, OrbitError>;
    fn get_job(&self, job_id: &str) -> Result<Option<Job>, OrbitError>;
    fn invocation_records(
        &self,
        _query: InvocationQuery,
    ) -> Result<Vec<InvocationRecord>, OrbitError> {
        Ok(Vec::new())
    }
    fn invocation_records_for_job_run_and_activity(
        &self,
        job_run_id: &str,
        activity_id: &str,
    ) -> Result<Vec<InvocationRecord>, OrbitError> {
        self.invocation_records(InvocationQuery {
            job_run_id: Some(job_run_id.to_string()),
            activity_id: Some(activity_id.to_string()),
            limit: 1_000_000,
            ..InvocationQuery::default()
        })
    }
    fn run_tool_with_context_and_role(
        &self,
        name: &str,
        input: Value,
        role: Role,
        tool_context: ToolContext,
    ) -> Result<Value, OrbitError>;
    fn invoke_activity(
        &self,
        _activity: Activity,
        _agent_cli: &str,
        _model: Option<&str>,
        _input: Value,
        _timeout_seconds: u64,
        _debug: bool,
    ) -> Result<ActivityInvocationResult, OrbitError> {
        Err(OrbitError::Execution(
            "invoke_activity is not implemented for this host".to_string(),
        ))
    }
    /// Create a task capturing a job run failure, skipping creation if an open
    /// task for the same `job_id` + `error_code` combination already exists.
    /// When `agent` and `model` are provided, they are recorded on the created
    /// task so attribution reflects the actual agent that was running.
    fn maybe_create_failure_task(
        &self,
        job_id: &str,
        run_id: &str,
        error_code: &str,
        error_message: &str,
        agent: Option<&str>,
        model: Option<&str>,
    ) -> Result<(), OrbitError>;
    fn resolved_agent_model_pair(&self, agent_cli: &str) -> Option<AgentModelPair> {
        resolve_agent_model_pair(agent_cli)
    }
    fn canonical_model_name(&self, _agent_cli: &str, model: Option<&str>) -> Option<String> {
        model
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
    }
    fn scoring_enabled(&self) -> bool;
    fn graph_editing(&self) -> bool;
    fn scoreboard_dir(&self) -> &Path;
    fn persist_invocation_trace(
        &self,
        _job_run_id: &str,
        _execution: &ExecutionContext,
        _trace: &InvocationTrace,
    ) -> Result<(), OrbitError> {
        Ok(())
    }
}

