    }

    fn data_root(&self) -> &std::path::Path {
        self.context.data_root()
    }

    fn activity_executor_registry(&self) -> &orbit_engine::ActivityExecutorRegistry {
        self.activity_executor_registry()
    }

    fn run_job_now_with_input_debug(
        &self,
        job_id: &str,
        _input: Value,
        _debug: bool,
    ) -> Result<orbit_engine::JobRunResult, OrbitError> {
        Err(OrbitError::Execution(format!(
            "v1 job dispatch is retired; refusing to run job '{job_id}' via RuntimeHost"
        )))
    }

    fn validate_activity_target_exists(
        &self,
        _target_type: JobTargetType,
        target_id: &str,
    ) -> Result<Activity, OrbitError> {
        Err(OrbitError::Execution(format!(
            "v1 activity lookup is retired; refusing to resolve activity '{target_id}'"
        )))
    }

    fn get_job(&self, _job_id: &str) -> Result<Option<orbit_common::types::Job>, OrbitError> {
        Ok(None)
    }

    fn resolved_agent_model_pair(&self, agent_cli: &str) -> Option<AgentModelPair> {
        self.configured_agent_model_pair(agent_cli)
    }

    fn canonical_model_name(&self, agent_cli: &str, model: Option<&str>) -> Option<String> {
        self.canonical_model_for_agent(agent_cli, model)
    }

    fn invocation_records(
        &self,
        query: InvocationQuery,
    ) -> Result<Vec<InvocationRecord>, OrbitError> {
        OrbitRuntime::invocation_records(self, query)
    }

    fn run_tool_with_context_and_role(
        &self,
        name: &str,
        input: Value,
        role: Role,
        tool_context: ToolContext,
    ) -> Result<Value, OrbitError> {
        OrbitRuntime::run_tool_with_context_and_role(self, name, input, role, tool_context)
    }

    fn invoke_activity(
        &self,
        activity: Activity,
        _agent_cli: &str,
        _model: Option<&str>,
        _input: Value,
        _timeout_seconds: u64,
        _debug: bool,
    ) -> Result<ActivityInvocationResult, OrbitError> {
        Err(OrbitError::Execution(format!(
            "v1 invoke_activity is retired; activity '{}' cannot be dispatched via RuntimeHost",
            activity.id
        )))
    }

    fn maybe_create_failure_task(
        &self,
        _job_id: &str,
        _run_id: &str,
        _error_code: &str,
        _error_message: &str,
        _agent: Option<&str>,
        _model: Option<&str>,
    ) -> Result<(), OrbitError> {
        Ok(())
    }

    fn scoring_enabled(&self) -> bool {
        self.context.scoring_enabled()
    }

    fn graph_editing(&self) -> bool {
        self.context.graph_editing()
    }

    fn scoreboard_dir(&self) -> &std::path::Path {
        &self.context.paths().scoreboard_dir
    }

    fn persist_invocation_trace(
        &self,
        job_run_id: &str,
        execution: &ExecutionContext,
        trace: &InvocationTrace,
    ) -> Result<(), OrbitError> {
        let requested_model = execution
            .model
            .as_deref()
            .or(execution.model_tier.as_deref());
        let (agent, model) =
            self.canonical_agent_model_identity(Some(&execution.agent_cli), requested_model);
        let store = open_invocation_store(self)?;
        store.insert_invocation_trace_record(&InvocationInsertParams {
            job_run_id: job_run_id.to_string(),
            activity_id: execution.activity.id.clone(),
            agent: agent.unwrap_or_else(|| normalize_agent_name(&execution.agent_cli)),
            model,
            task_ids: associated_task_ids(&execution.input),
            trace: trace.clone(),
        })?;

        if let Err(error) =
            token_scoreboard::write_token_scoreboard(&self.paths().scoreboard_dir, &store)
        {
            eprintln!("orbit: failed to refresh tokens scoreboard: {error}");
        }

        Ok(())
    }
}

impl Session {
    pub fn new(
        provider: impl Into<String>,
        model: impl Into<String>,
        system_prompt: impl Into<String>,
        audit_tag: Option<String>,
    ) -> Self {
        let counter = SESSION_COUNTER.fetch_add(1, Ordering::Relaxed);
        let ts_us = Utc::now().timestamp_micros();
        let id = format!("S{ts_us:x}-{counter:x}");
        Self {
            id,
            provider: provider.into(),
            model: model.into(),
            system_prompt: system_prompt.into(),
            history: Vec::new(),
            audit_tag,
            spawn_emitted: false,
        }
    }

    pub fn id(&self) -> &str {
        &self.id
    }

    pub fn provider(&self) -> &str {
        &self.provider
    }

    pub fn model(&self) -> &str {
        &self.model
    }

    pub fn system_prompt(&self) -> &str {
        &self.system_prompt
    }

    pub fn audit_tag(&self) -> Option<&str> {
        self.audit_tag.as_deref()
    }

    pub fn history(&self) -> &[Message] {
        &self.history
    }

    pub fn history_mut(&mut self) -> &mut Vec<Message> {
        &mut self.history
    }

    pub fn append_message(&mut self, msg: Message) {
        self.history.push(msg);
    }

    pub fn ensure_spawn_emitted(
        &mut self,
        run_id: &str,
        task_id: Option<&str>,
        sink: &dyn AuditSink,
    ) {
        if self.spawn_emitted {
            return;
        }
        sink.emit(&LoopAuditEvent::SessionSpawn {
            ts: Utc::now(),
            run_id: run_id.to_string(),
            session_id: self.id.clone(),
            provider: self.provider.clone(),
            model: self.model.clone(),
            task_id: task_id.map(|s| s.to_string()),
            audit_tag: self.audit_tag.clone(),
        });
        self.spawn_emitted = true;
    }

    /// Run one `AgentLoop` turn against this session. Thin wrapper that
    /// threads the runtime dependencies through to [`AgentLoop::run`].
    /// Appends the user prompt, runs the loop, appends the assistant reply;
    /// mutating, per AC contract.
    #[allow(clippy::too_many_arguments)]
    pub fn send(
        &mut self,
        cfg: &AgentLoopConfig,
        transport: &dyn LoopTransport,
        registry: &ToolRegistry,
        tool_ctx: &ToolContext,
        sink: &dyn AuditSink,
        user_prompt: &str,
    ) -> Result<LoopOutcome, AgentLoopError> {
        AgentLoop::run(self, cfg, transport, registry, tool_ctx, sink, user_prompt)
    }

    pub fn close(self, run_id: &str, sink: &dyn AuditSink) {
        sink.emit(&LoopAuditEvent::SessionClose {
            ts: Utc::now(),
            run_id: run_id.to_string(),
            session_id: self.id.clone(),
            reason: "caller_closed".to_string(),
        });
    }

    /// Close the session without emitting a SessionClose event. Use when the
    /// loop itself has already recorded the termination condition (e.g. a
    /// guardrail error was the "close" reason).
    pub fn drop_quiet(self) {}
}

impl AgentLoop {
    #[allow(clippy::too_many_arguments)]
    pub fn run(
        session: &mut Session,
        cfg: &AgentLoopConfig,
        transport: &dyn LoopTransport,
        registry: &ToolRegistry,
        tool_ctx: &ToolContext,
        sink: &dyn AuditSink,
        user_prompt: &str,
    ) -> Result<LoopOutcome, AgentLoopError> {
        session.ensure_spawn_emitted(&cfg.run_id, cfg.task_id.as_deref(), sink);

        session.append_message(Message::user_text(user_prompt));

        let advertised: Vec<String> = match cfg.advertised_tools.as_ref() {
            Some(set) => set.clone(),
            None => cfg.tool_allowlist.clone(),
        };
        let tool_specs = build_tool_specs(registry, &advertised);
        let allowlist: Vec<&str> = cfg.tool_allowlist.iter().map(String::as_str).collect();

        let started = Instant::now();
        let mut total_tokens_observed: u64 = 0;
        let mut cumulative_usage = TurnUsage::default();
        let mut trace: Vec<IterationTrace> = Vec::new();
        let mut last_text_reply = String::new();
        let mut iteration: u32 = 0;

        loop {
            iteration += 1;
            check_deadline(cfg, started)?;
            if iteration > cfg.max_iterations {
                return Err(AgentLoopError::MaxIterations {
                    limit: cfg.max_iterations,
                    observed: iteration - 1,
                });
            }

            let turn_req = TurnRequest {
                system: if session.system_prompt().is_empty() {
                    None
                } else {
                    Some(session.system_prompt())
                },
                messages: session.history(),
                tools: &tool_specs,
                cache_hint: cfg.cache_hint,
                max_response_tokens: cfg.max_response_tokens,
            };

            let TurnResponse {
                content,
                stop_reason,
                usage,
                raw_request_body,
                raw_response_body,
                endpoint,
                http_status,
            } = invoke_transport(transport, sink, cfg, session.id(), iteration, &turn_req)?;

            total_tokens_observed = total_tokens_observed
                .saturating_add(usage.input_tokens)
                .saturating_add(usage.output_tokens)
                .saturating_add(usage.cache_creation_input_tokens);
            accumulate(&mut cumulative_usage, &usage);

            // Minimal debug hook — raw bytes retained in audit, not dropped.
            drop((raw_request_body, raw_response_body, endpoint, http_status));

            if total_tokens_observed > cfg.max_total_tokens {
                return Err(AgentLoopError::TokenBudget {
                    limit: cfg.max_total_tokens,
                    observed: total_tokens_observed,
                });
            }
            check_deadline(cfg, started)?;

            let (text_part, assistant_blocks, tool_calls) = classify_content(&content);
            if !text_part.is_empty() {
                last_text_reply = text_part;
            }

            session.append_message(Message::assistant(assistant_blocks));

            let mut iter_tool_names = Vec::new();
            let mut iter_denials = Vec::new();
            let mut user_tool_results: Vec<ContentBlock> = Vec::new();

            for (tool_use_id, tool_name, input) in tool_calls {
                iter_tool_names.push(tool_name.clone());

                if !is_tool_allowed(&tool_name, &allowlist) {
                    let reason = "tool not in allowlist".to_string();
                    let denial_payload = serde_json::json!({
                        "tool_name": &tool_name,
                        "tool_use_id": &tool_use_id,
                        "reason": &reason,
                        "input": &input,
                    });
                    let _ =
                        sink.write_blob(&serde_json::to_vec(&denial_payload).unwrap_or_default());
                    sink.emit(&LoopAuditEvent::PolicyDenial {
                        ts: Utc::now(),
                        run_id: cfg.run_id.clone(),
                        session_id: session.id().to_string(),
                        iteration,
                        tool_name: tool_name.clone(),
                        reason,
                    });
                    iter_denials.push(tool_name.clone());
                    sink.emit(&LoopAuditEvent::IterationBoundary {
                        ts: Utc::now(),
                        run_id: cfg.run_id.clone(),
                        session_id: session.id().to_string(),
                        iteration,
                        continues: false,
                    });
                    trace.push(IterationTrace {
                        iteration,
                        stop_reason,
                        tool_calls: iter_tool_names,
                        policy_denials: iter_denials,
                        usage: usage.clone(),
                    });
                    return Err(AgentLoopError::PolicyDenied {
                        tool_name,
                        iteration,
                    });
                }

                let input_bytes = serde_json::to_vec(&input).unwrap_or_default();
                let input_sha256 = sink.write_blob(&input_bytes);
                sink.emit(&LoopAuditEvent::ToolCallRequested {
                    ts: Utc::now(),
                    run_id: cfg.run_id.clone(),
                    session_id: session.id().to_string(),
                    iteration,
                    tool_name: tool_name.clone(),
                    tool_use_id: tool_use_id.clone(),
                    input_sha256,
                });

                let outcome = dispatch(registry, tool_ctx, &tool_name, input);
                let output_bytes = serde_json::to_vec(&outcome.output).unwrap_or_default();
                let output_sha256 = sink.write_blob(&output_bytes);
                sink.emit(&LoopAuditEvent::ToolCallResult {
                    ts: Utc::now(),
                    run_id: cfg.run_id.clone(),
                    session_id: session.id().to_string(),
                    iteration,
                    tool_name: tool_name.clone(),
                    tool_use_id: tool_use_id.clone(),
                    outcome: if outcome.is_error {
                        "error".to_string()
                    } else {
                        "ok".to_string()
                    },
                    output_sha256,
                    duration_ms: outcome.duration_ms,
                });

                let tool_text = match serde_json::to_string(&outcome.output) {
                    Ok(s) => s,
                    Err(err) => format!("{{\"error\":\"serialize: {err}\"}}"),
                };
                user_tool_results.push(ContentBlock::ToolResult {
                    tool_use_id,
                    content: tool_text,
                    is_error: outcome.is_error,
                });
            }

            let continues =
                matches!(stop_reason, StopReason::ToolUse) && !user_tool_results.is_empty();
            sink.emit(&LoopAuditEvent::IterationBoundary {
                ts: Utc::now(),
                run_id: cfg.run_id.clone(),
                session_id: session.id().to_string(),
                iteration,
                continues,
            });
            trace.push(IterationTrace {
                iteration,
                stop_reason,
                tool_calls: iter_tool_names,
                policy_denials: iter_denials,
                usage: usage.clone(),
            });

            if !continues {
                let terminate_reason = match stop_reason {
                    StopReason::MaxTokens => TerminateReason::MaxTokens,
                    StopReason::EndTurn => TerminateReason::Stop,
                    _ => TerminateReason::Other,
                };
                return Ok(LoopOutcome {
                    final_message: last_text_reply,
                    usage: cumulative_usage,
                    terminate_reason,
                    trace,
                });
            }

            session.append_message(Message::user_blocks(user_tool_results));
        }
    }
}

pub struct DispatchOutcome {
    pub output: Value,
    pub is_error: bool,
    pub duration_ms: u128,
}
